const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Correct path for your AI response
    let rawText = item.json.output?.[0]?.content?.[0]?.text || '{}';

    // Remove markdown fences if present
    rawText = rawText
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();

    const parsed = JSON.parse(rawText);

    results.push({
      json: {
        riskCategory: parsed.riskCategory || 'Unknown',
        redFlags: parsed.redFlags || [],
        redFlagText: (parsed.redFlags && parsed.redFlags.length > 0)
          ? parsed.redFlags.join(', ')
          : 'None',
        income: parsed.income || '',
        geography: parsed.geography || '',
        occupation: parsed.occupation || ''
      }
    });

  } catch (error) {
    results.push({
      json: {
        riskCategory: 'Unknown',
        redFlags: [],
        redFlagText: 'None',
        income: '',
        geography: '',
        occupation: '',
        error: error.message
      }
    });
  }
}

return results;

const income = Number($json.Income || 0);
const geography = String($json.Geography || '').trim();
const occupation = String($json.Occupation || '').trim();

const errors = [];

if (!income || income <= 0) {
  errors.push('Income must be greater than 0');
}

if (!geography) {
  errors.push('Geography is required');
}

if (!occupation) {
  errors.push('Occupation is required');
}

return [
  {
    json: {
      Income: income,
      Geography: geography.toUpperCase(),
      Occupation: occupation,
      isValid: errors.length === 0,
      validationErrors: errors.length ? errors.join(', ') : '',
      createdAt: new Date().toISOString()
    }
  }
];
